@using sv_97f3774925e7468bb2a7672b9c6719c7.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp" title="@Message.SentAt.ToString("g")">@RelativeTime</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="OpenThread">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="OpenThread" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😊</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker-container">
            <EmojiPicker OnEmojiSelected="HandleReaction" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private string RelativeTime => FormatRelative(Message.SentAt);

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task OpenThread() => await OnOpenThread.InvokeAsync(Message.Id);

    private async Task HandleReaction(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelative(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background: rgba(255, 255, 255, 0.04);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.93rem;
    color: #d0d0d0;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border-radius: 12px;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.1);
    font-size: 0.82rem;
    color: #ccc;
    cursor: default;
}

.thread-link {
    background: transparent;
    border: none;
    color: #5b8dee;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #2a2d32;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.action-btn {
    background: transparent;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.action-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

.emoji-picker-container {
    position: absolute;
    top: -8px;
    right: 8px;
    z-index: 10;
    transform: translateY(-100%);
}

