@using sv_97f3774925e7468bb2a7672b9c6719c7.Services

<div class="channel-list">
    <h2 class="sidebar-title">Channels</h2>
    <div class="channel-items">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #1e2024;
    border-right: 1px solid #333;
    overflow: hidden;
}

.sidebar-title {
    font-size: 1rem;
    font-weight: 700;
    color: #e0e0e0;
    padding: 16px 16px 8px;
    margin: 0;
    letter-spacing: 0.02em;
}

.channel-items {
    flex: 1;
    overflow-y: auto;
    padding: 4px 8px;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

@using sv_97f3774925e7468bb2a7672b9c6719c7.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2 class="area-channel-name"># @Channel.Name</h2>
            <span class="area-channel-desc">@Channel.Description</span>
        </div>

        <div class="message-list" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var msg in Messages)
            {
                <MessageItem Message="msg"
                             ReplyCount="GetReplyCount(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSend="HandleSend" />
    }
    else
    {
        <div class="empty-state">Select a channel to start chatting</div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleSend(string content) =>
        await OnSendMessage.InvokeAsync(content);

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers load more via JS interop would be ideal,
        // but we expose the event for the parent to handle
        await OnLoadMore.InvokeAsync();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #23262b;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #3a3d42;
    background: #2a2d32;
    flex-shrink: 0;
