    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

@using sv_97f3774925e7468bb2a7672b9c6719c7.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3 class="thread-title">Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var msg in ThreadMessages)
            {
                <div class="thread-message">
                    <div class="thread-msg-header">
                        <span class="author">@msg.Author</span>
                        <span class="timestamp" title="@msg.SentAt.ToString("g")">@FormatRelative(msg.SentAt)</span>
                    </div>
                    <div class="thread-msg-content">@msg.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply…"
                      ButtonLabel="Reply"
                      OnSend="HandleReply" />
    }
</div>

