toolArgs.file_text:
@using sv_97f3774925e7468bb2a7672b9c6719c7.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3 class="thread-title">Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var msg in ThreadMessages)
            {
                <div class="thread-message">
                    <div class="thread-msg-header">
                        <span class="author">@msg.Author</span>
                        <span class="timestamp" title="@msg.SentAt.ToString("g")">@FormatRelative(msg.SentAt)</span>
                    </div>
                    <div class="thread-msg-content">@msg.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply…"
                      ButtonLabel="Reply"
                      OnSend="HandleReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private async Task HandleReply(string content) =>
        await OnSendReply.InvokeAsync(content);

    private static string FormatRelative(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #1e2024;
    border-left: 1px solid #333;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #3a3d42;
    background: #2a2d32;
    flex-shrink: 0;
}

.thread-title {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #e0e0e0;
}

.close-btn {
    background: transparent;
    border: none;
    color: #999;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #e0e0e0;
}

.thread-root {
    padding: 12px 16px;
    border-bottom: 1px solid #3a3d42;
    background: rgba(255, 255, 255, 0.03);
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #e0e0e0;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.88rem;
    color: #bbb;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 6px 16px;
    font-size: 0.75rem;
    color: #888;
    border-bottom: 1px solid #3a3d42;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-message {
    padding: 6px 16px;
}

.thread-msg-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .author {
    font-weight: 700;
    font-size: 0.88rem;
    color: #e0e0e0;
}

::deep .timestamp {
    font-size: 0.72rem;
    color: #888;
}

.thread-msg-content {
    font-size: 0.88rem;
    color: #d0d0d0;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

