.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    display: flex;
    background: #23262b;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

export function registerScrollHandler(element, dotNetRef) {
    if (!element) return;
    element.addEventListener('scroll', () => {
        if (element.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    });
}

export function scrollToBottom(element) {
    if (!element) return;
    element.scrollTop = element.scrollHeight;
}

@page "/chat"
@layout sv_97f3774925e7468bb2a7672b9c6719c7.Components.Chat.ChatLayout
@rendermode InteractiveServer

@using sv_97f3774925e7468bb2a7672b9c6719c7.Services
@using sv_97f3774925e7468bb2a7672b9c6719c7.Components.Chat

@inject IChatService ChatService
@inject IJSRuntime JS

@implements IAsyncDisposable

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelList Channels="channels"
                     ActiveChannelId="activeChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(threadRootMessage is not null ? "" : "expanded")">
        <MessageArea Channel="activeChannel"
                     Messages="messages"
                     ThreadReplyCounts="threadReplyCounts"
                     IsLoadingMore="isLoadingMore"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadMoreMessages" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private int activeChannelId;
    private Channel? activeChannel;

    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    private IJSObjectReference? jsModule;
    private DotNetObjectReference<Chat>? dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadReplyCounts = [];
        hasMoreMessages = true;

        CloseThreadSync();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;

        BuildThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        messages.InsertRange(0, older);

        BuildThreadReplyCounts();

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread() => CloseThreadSync();

    private void CloseThreadSync()
    {
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            activeChannelId, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] =
            threadReplyCounts.GetValueOrDefault(threadRootMessage.Id) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var idx = messages.FindIndex(m => m.Id == args.MessageId);
        if (idx >= 0)
        {
            var msg = messages[idx];
            var reactions = new List<Reaction>(msg.Reactions);
            var existing = reactions.FindIndex(r => r.Emoji == args.Emoji);
            if (existing >= 0)
            {
                var r = reactions[existing];
                var users = new List<string>(r.Users) { "You" };
                reactions[existing] = new Reaction(r.Emoji, users);
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            messages[idx] = msg with { Reactions = reactions };
        }
    }

    private void BuildThreadReplyCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    [JSInvokable]
    public async Task OnScrolledToTop() => await LoadMoreMessages();

    public async ValueTask DisposeAsync()
    {
        dotNetRef?.Dispose();
        if (jsModule is not null)
        {
            await jsModule.DisposeAsync();
        }
    }
}

.chat-container {
