    display: flex;
    background: #23262b;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

export function registerScrollHandler(element, dotNetRef) {
    if (!element) return;
    element.addEventListener('scroll', () => {
